import{_ as r,o as e,c as t,a2 as l}from"./chunks/framework.DnrXFDHb.js";const g=JSON.parse('{"title":"01-3 油輪產業結構","description":"","frontmatter":{},"headers":[],"relativePath":"Deep32Q知識庫/產業洞察/航運產業/01_次產業結構/01-3_油輪.md","filePath":"Deep32Q知識庫/產業洞察/航運產業/01_次產業結構/01-3_油輪.md"}'),i={name:"Deep32Q知識庫/產業洞察/航運產業/01_次產業結構/01-3_油輪.md"};function n(o,a,s,c,d,h){return e(),t("div",null,[...a[0]||(a[0]=[l('<h1 id="_01-3-油輪產業結構" tabindex="-1">01-3 油輪產業結構 <a class="header-anchor" href="#_01-3-油輪產業結構" aria-label="Permalink to &quot;01-3 油輪產業結構&quot;">​</a></h1><h2 id="一、船型分類" tabindex="-1">一、船型分類 <a class="header-anchor" href="#一、船型分類" aria-label="Permalink to &quot;一、船型分類&quot;">​</a></h2><h3 id="_1-vlcc-very-large-crude-carrier-超大型油輪" tabindex="-1">1. VLCC（Very Large Crude Carrier，超大型油輪） <a class="header-anchor" href="#_1-vlcc-very-large-crude-carrier-超大型油輪" aria-label="Permalink to &quot;1. VLCC（Very Large Crude Carrier，超大型油輪）&quot;">​</a></h3><ul><li><strong>載重噸位</strong>：約 200,000～320,000 DWT</li><li><strong>用途</strong>：長距離原油運輸（中東—亞洲、南美—亞洲）</li><li><strong>2025 年展望</strong>：船隊增長約 0.4%，中國原油進口為關鍵驅動因素；2025 年底 VLCC 運價超過 10 年平均 60% 以上，日收益峰值突破 10 萬美元</li></ul><h3 id="_2-suezmax-蘇伊士型" tabindex="-1">2. Suezmax（蘇伊士型） <a class="header-anchor" href="#_2-suezmax-蘇伊士型" aria-label="Permalink to &quot;2. Suezmax（蘇伊士型）&quot;">​</a></h3><ul><li><strong>載重噸位</strong>：約 160,000～200,000 DWT（可通過蘇伊士運河的最大原油輪）</li><li><strong>用途</strong>：中東—歐洲、中東—美國墨西哥灣</li><li><strong>2025 年展望</strong>：船隊增長約 4.0%（高於需求增長 2.3%），但長距離貿易與紅海繞航帶來的噸海里需求仍支撐運價；年底運價超過 10 年平均 60% 以上</li></ul><h3 id="_3-aframax" tabindex="-1">3. Aframax <a class="header-anchor" href="#_3-aframax" aria-label="Permalink to &quot;3. Aframax&quot;">​</a></h3><ul><li><strong>載重噸位</strong>：約 80,000～120,000 DWT</li><li><strong>用途</strong>：區域性成品油運輸、中短程原油（地中海—歐洲、美國境內）</li><li><strong>2025 年展望</strong>：船隊增長約 0.5%，需求增長約 1.2%；Aframax/LR（長程）子類別增長最快（9.4%），但可能面臨供過於求</li></ul><h2 id="二、運價指數" tabindex="-1">二、運價指數 <a class="header-anchor" href="#二、運價指數" aria-label="Permalink to &quot;二、運價指數&quot;">​</a></h2><h3 id="bdti-baltic-dirty-tanker-index-汙油輪指數" tabindex="-1">BDTI（Baltic Dirty Tanker Index，汙油輪指數） <a class="header-anchor" href="#bdti-baltic-dirty-tanker-index-汙油輪指數" aria-label="Permalink to &quot;BDTI（Baltic Dirty Tanker Index，汙油輪指數）&quot;">​</a></h3><ul><li><strong>追蹤對象</strong>：運輸成品油（汽油、柴油、燃料油等）的油輪運費</li><li><strong>2025 年區間</strong>：約 $700～$1,600</li><li><strong>影響因素</strong>：紅海繞航、貿易路線變化、船隊供應</li></ul><h3 id="bcti-baltic-clean-tanker-index-乾淨油輪指數" tabindex="-1">BCTI（Baltic Clean Tanker Index，乾淨油輪指數） <a class="header-anchor" href="#bcti-baltic-clean-tanker-index-乾淨油輪指數" aria-label="Permalink to &quot;BCTI（Baltic Clean Tanker Index，乾淨油輪指數）&quot;">​</a></h3><ul><li><strong>追蹤對象</strong>：運輸乾淨油品（石腦油、輕柴油等）的油輪運費</li><li><strong>與 BDTI 關係</strong>：反映成品油市場供需，常與汙油輪市場聯動</li></ul><h2 id="三、opec-對油輪市場的影響" tabindex="-1">三、OPEC+ 對油輪市場的影響 <a class="header-anchor" href="#三、opec-對油輪市場的影響" aria-label="Permalink to &quot;三、OPEC+ 對油輪市場的影響&quot;">​</a></h2><ul><li><strong>2025 年產量政策</strong>：OPEC+ 加速解除自願減產，計畫重新投入約 220 萬桶/日</li><li><strong>實際效果</strong>：截至 2025 年 6 月，增产計畫尚未完全轉化為出口增加；若減產完全解除，預估油市過剩約 140 萬桶/日</li><li><strong>對油輪的間接影響</strong>：雖然短期造成原油過剩壓低運價，但 OPEC+ 產量最終轉為實際出口後，將增加長距離貿易需求，有利油輪市場</li><li><strong>非 OPEC+ 供應</strong>：2025 年全球供應增長約 190 萬桶/日，非 OPEC+ 貢獻近半數增量（美國、巴西、圭亞那）</li></ul><h3 id="_2025-2026-關鍵觀察" tabindex="-1">2025-2026 關鍵觀察 <a class="header-anchor" href="#_2025-2026-關鍵觀察" aria-label="Permalink to &quot;2025-2026 關鍵觀察&quot;">​</a></h3><ul><li>IEA 預估全球石油需求增長約 110 萬桶/日（達 1.039 億桶/日）</li><li>紅海/蘇伊士繞航持續增加噸海里需求，若正常通航恢復可能削弱運價</li><li>2025 年底 VLCC/Suezmax 運價均創下超過 10 年平均 60% 以上的高點</li></ul><blockquote><p>資料來源：S&amp;P Global Energy、Riviera Marine Research、AXSMarine 2025-2026 油輪供應情景分析、TankersInternational.com 2025 年度回顧、Investing.com、DNV 油輪市場展望</p></blockquote>',18)])])}const _=r(i,[["render",n]]);export{g as __pageData,_ as default};
